import{_ as s,c as e,o as a,a as n}from"./app.606ab571.js";const F=JSON.parse('{"title":"Logging","description":"","frontmatter":{},"headers":[{"level":2,"title":"What We Use","slug":"what-we-use","link":"#what-we-use","children":[]},{"level":2,"title":"CorrelationId","slug":"correlationid","link":"#correlationid","children":[{"level":3,"title":"CorrelationContext","slug":"correlationcontext","link":"#correlationcontext","children":[]}]},{"level":2,"title":"Where We Log","slug":"where-we-log","link":"#where-we-log","children":[{"level":3,"title":"Application layer \u2014 yes","slug":"application-layer-\u2014-yes","link":"#application-layer-\u2014-yes","children":[]},{"level":3,"title":"Query handlers \u2014 no","slug":"query-handlers-\u2014-no","link":"#query-handlers-\u2014-no","children":[]},{"level":3,"title":"Infrastructure layer \u2014 no","slug":"infrastructure-layer-\u2014-no","link":"#infrastructure-layer-\u2014-no","children":[]},{"level":3,"title":"Domain layer \u2014 never","slug":"domain-layer-\u2014-never","link":"#domain-layer-\u2014-never","children":[]}]},{"level":2,"title":"What We Log","slug":"what-we-log","link":"#what-we-log","children":[{"level":3,"title":"Log levels","slug":"log-levels","link":"#log-levels","children":[]}]},{"level":2,"title":"Logged Components","slug":"logged-components","link":"#logged-components","children":[{"level":3,"title":"CorrelationIdMiddleware","slug":"correlationidmiddleware","link":"#correlationidmiddleware","children":[]},{"level":3,"title":"OutboxProcessorService","slug":"outboxprocessorservice","link":"#outboxprocessorservice","children":[]},{"level":3,"title":"EventDispatcher","slug":"eventdispatcher","link":"#eventdispatcher","children":[]},{"level":3,"title":"Command handlers","slug":"command-handlers","link":"#command-handlers","children":[]},{"level":3,"title":"Event handlers","slug":"event-handlers","link":"#event-handlers","children":[]}]},{"level":2,"title":"Log Output","slug":"log-output","link":"#log-output","children":[]},{"level":2,"title":"Sinks","slug":"sinks","link":"#sinks","children":[]}],"relativePath":"logging.md"}'),o={name:"logging.md"},l=n(`<h1 id="logging" tabindex="-1">Logging <a class="header-anchor" href="#logging" aria-hidden="true">#</a></h1><h2 id="what-we-use" tabindex="-1">What We Use <a class="header-anchor" href="#what-we-use" aria-hidden="true">#</a></h2><p><strong>Serilog</strong> with structured logging. Instead of plain text strings, every log entry is a structured object with named properties that can be queried individually.</p><p>Plain text logging:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki"><code><span class="line"><span style="color:#A6ACCD;">[INFO] Reservation 3f2a created for screening 9b1c</span></span>
<span class="line"><span style="color:#A6ACCD;"></span></span></code></pre></div><p>Structured logging:</p><div class="language-json"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki"><code><span class="line"><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C792EA;">timestamp</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">2026-05-06T10:23:11Z</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C792EA;">level</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">Information</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C792EA;">message</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">Reservation created</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C792EA;">ReservationId</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">3f2a...</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C792EA;">ScreeningId</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">9b1c...</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C792EA;">CorrelationId</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">7d4e...</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C792EA;">SeatCount</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#F78C6C;">2</span></span>
<span class="line"><span style="color:#89DDFF;">}</span></span>
<span class="line"></span></code></pre></div><p>The difference is that fields are queryable \u2014 in a log viewer you can filter by <code>ReservationId</code> and see every log entry related to that reservation across both the API and the Worker.</p><h2 id="correlationid" tabindex="-1">CorrelationId <a class="header-anchor" href="#correlationid" aria-hidden="true">#</a></h2><p>Every HTTP request is assigned a <code>CorrelationId</code> that flows through the entire system \u2014 from the initial API request through the outbox into the background worker.</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki"><code><span class="line"><span style="color:#A6ACCD;">HTTP Request</span></span>
<span class="line"><span style="color:#A6ACCD;">    \u2502</span></span>
<span class="line"><span style="color:#A6ACCD;">    \u25BC</span></span>
<span class="line"><span style="color:#A6ACCD;">CorrelationIdMiddleware</span></span>
<span class="line"><span style="color:#A6ACCD;">    \u251C\u2500\u2500 reads X-Correlation-Id header (or generates a new GUID)</span></span>
<span class="line"><span style="color:#A6ACCD;">    \u251C\u2500\u2500 writes it back to the response header</span></span>
<span class="line"><span style="color:#A6ACCD;">    \u251C\u2500\u2500 sets CorrelationContext.CorrelationId (scoped service)</span></span>
<span class="line"><span style="color:#A6ACCD;">    \u2514\u2500\u2500 pushes it into Serilog LogContext</span></span>
<span class="line"><span style="color:#A6ACCD;">         \u2502</span></span>
<span class="line"><span style="color:#A6ACCD;">         \u25BC</span></span>
<span class="line"><span style="color:#A6ACCD;">    Command Handler \u2192 SaveChangesAsync</span></span>
<span class="line"><span style="color:#A6ACCD;">         \u2514\u2500\u2500 OutboxMessage.CorrelationId = CorrelationContext.CorrelationId</span></span>
<span class="line"><span style="color:#A6ACCD;">                                                \u2502</span></span>
<span class="line"><span style="color:#A6ACCD;">                                                \u25BC</span></span>
<span class="line"><span style="color:#A6ACCD;">                                        OutboxProcessorService (Worker)</span></span>
<span class="line"><span style="color:#A6ACCD;">                                            \u2514\u2500\u2500 LogContext.PushProperty(&quot;CorrelationId&quot;, msg.CorrelationId)</span></span>
<span class="line"><span style="color:#A6ACCD;">                                                 \u2502</span></span>
<span class="line"><span style="color:#A6ACCD;">                                                 \u25BC</span></span>
<span class="line"><span style="color:#A6ACCD;">                                            Event Handlers</span></span>
<span class="line"><span style="color:#A6ACCD;">                                                \u2514\u2500\u2500 all logs automatically include CorrelationId</span></span>
<span class="line"><span style="color:#A6ACCD;"></span></span></code></pre></div><p>This means you can take the <code>X-Correlation-Id</code> from any API response and find every log entry related to that request \u2014 including what the worker did minutes later.</p><h3 id="correlationcontext" tabindex="-1">CorrelationContext <a class="header-anchor" href="#correlationcontext" aria-hidden="true">#</a></h3><p>A scoped service that carries the correlationId through the request:</p><div class="language-csharp"><button title="Copy Code" class="copy"></button><span class="lang">csharp</span><pre class="shiki"><code><span class="line"><span style="color:#C792EA;">public</span><span style="color:#A6ACCD;"> </span><span style="color:#F78C6C;">class</span><span style="color:#A6ACCD;"> </span><span style="color:#FFCB6B;">CorrelationContext</span></span>
<span class="line"><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#C792EA;">public</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">string</span><span style="color:#A6ACCD;"> </span><span style="color:#FFCB6B;">CorrelationId</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">{</span><span style="color:#A6ACCD;"> </span><span style="color:#F78C6C;">get</span><span style="color:#89DDFF;">;</span><span style="color:#A6ACCD;"> </span><span style="color:#F78C6C;">set</span><span style="color:#89DDFF;">;</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">}</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> Guid</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">NewGuid</span><span style="color:#89DDFF;">().</span><span style="color:#82AAFF;">ToString</span><span style="color:#89DDFF;">();</span></span>
<span class="line"><span style="color:#89DDFF;">}</span></span>
<span class="line"></span></code></pre></div><p>Set by middleware, injected into <code>DbContext</code> to stamp outbox messages. Scoped to the request lifetime so each request gets its own instance.</p><h2 id="where-we-log" tabindex="-1">Where We Log <a class="header-anchor" href="#where-we-log" aria-hidden="true">#</a></h2><h3 id="application-layer-\u2014-yes" tabindex="-1">Application layer \u2014 yes <a class="header-anchor" href="#application-layer-\u2014-yes" aria-hidden="true">#</a></h3><p>This is where business operations happen and where failures matter. Both command handlers and event handlers log here.</p><h3 id="query-handlers-\u2014-no" tabindex="-1">Query handlers \u2014 no <a class="header-anchor" href="#query-handlers-\u2014-no" aria-hidden="true">#</a></h3><p>Queries are read-only and low-risk. Logging them adds noise without value.</p><h3 id="infrastructure-layer-\u2014-no" tabindex="-1">Infrastructure layer \u2014 no <a class="header-anchor" href="#infrastructure-layer-\u2014-no" aria-hidden="true">#</a></h3><p>EF Core and Redis driver logs cover normal operations. We only let infrastructure exceptions bubble up and get logged by the application layer.</p><h3 id="domain-layer-\u2014-never" tabindex="-1">Domain layer \u2014 never <a class="header-anchor" href="#domain-layer-\u2014-never" aria-hidden="true">#</a></h3><p>Domain has no logging dependency and should not have one.</p><h2 id="what-we-log" tabindex="-1">What We Log <a class="header-anchor" href="#what-we-log" aria-hidden="true">#</a></h2><p>The rule: <strong>log decisions and outcomes, not mechanics.</strong></p><table><thead><tr><th>\u2705 Log this</th><th>\u274C Not this</th></tr></thead><tbody><tr><td>&quot;Reservation created&quot;</td><td>&quot;Called SaveChangesAsync&quot;</td></tr><tr><td>&quot;Payment completed for reservation X&quot;</td><td>&quot;Called StringSetAsync&quot;</td></tr><tr><td>&quot;Seat already locked&quot;</td><td>&quot;Acquired Redis connection&quot;</td></tr><tr><td>&quot;Message dead-lettered after 5 retries&quot;</td><td>&quot;Fetched 20 outbox messages&quot;</td></tr></tbody></table><h3 id="log-levels" tabindex="-1">Log levels <a class="header-anchor" href="#log-levels" aria-hidden="true">#</a></h3><table><thead><tr><th>Level</th><th>When</th></tr></thead><tbody><tr><td><code>Information</code></td><td>Successful business operation completed</td></tr><tr><td><code>Warning</code></td><td>Expected failure \u2014 seat locked, not found, duplicate ignored</td></tr><tr><td><code>Error</code></td><td>Unexpected failure \u2014 exception, dead-letter, deserialization failure</td></tr></tbody></table><h2 id="logged-components" tabindex="-1">Logged Components <a class="header-anchor" href="#logged-components" aria-hidden="true">#</a></h2><h3 id="correlationidmiddleware" tabindex="-1">CorrelationIdMiddleware <a class="header-anchor" href="#correlationidmiddleware" aria-hidden="true">#</a></h3><ul><li>Logs nothing directly \u2014 pushes <code>CorrelationId</code> into <code>LogContext</code> for all downstream logs</li></ul><h3 id="outboxprocessorservice" tabindex="-1">OutboxProcessorService <a class="header-anchor" href="#outboxprocessorservice" aria-hidden="true">#</a></h3><ul><li>Message processed successfully</li><li>Message failed with retry scheduled (Warning + exception)</li><li>Message dead-lettered after 5 retries (Error + exception)</li></ul><h3 id="eventdispatcher" tabindex="-1">EventDispatcher <a class="header-anchor" href="#eventdispatcher" aria-hidden="true">#</a></h3><ul><li>Event type being dispatched and handler count</li><li>Dispatch completed successfully</li><li>Deserialization failure (Error)</li></ul><h3 id="command-handlers" tabindex="-1">Command handlers <a class="header-anchor" href="#command-handlers" aria-hidden="true">#</a></h3><ul><li><code>CreateReservationHandler</code> \u2014 reservation created, seat lock failures, concurrency conflicts</li><li><code>CompletePaymentHandler</code> \u2014 payment completed</li><li><code>FailPaymentHandler</code> \u2014 payment failed</li></ul><h3 id="event-handlers" tabindex="-1">Event handlers <a class="header-anchor" href="#event-handlers" aria-hidden="true">#</a></h3><ul><li><code>ReservationCreatedHandler</code> \u2014 payment created with amount</li><li><code>ReservationConfirmedHandler</code> \u2014 seats marked as sold with count</li><li><code>PaymentCompletedHandler</code> \u2014 reservation confirmed</li></ul><h2 id="log-output" tabindex="-1">Log Output <a class="header-anchor" href="#log-output" aria-hidden="true">#</a></h2><p>All logs include <code>CorrelationId</code> automatically via <code>LogContext</code>. The outbox worker additionally includes <code>MessageType</code> and <code>MessageId</code> per message:</p><div class="language-json"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki"><code><span class="line"><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C792EA;">timestamp</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">2026-05-06T10:23:15Z</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C792EA;">level</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">Information</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C792EA;">message</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">Outbox message processed</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C792EA;">CorrelationId</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">7d4e-...</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C792EA;">MessageType</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">PaymentCompleted</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C792EA;">MessageId</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">a1b2-...</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C792EA;">SourceContext</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">Ticketing.Application.Outbox.OutboxProcessorService</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#89DDFF;">}</span></span>
<span class="line"></span></code></pre></div><h2 id="sinks" tabindex="-1">Sinks <a class="header-anchor" href="#sinks" aria-hidden="true">#</a></h2><table><thead><tr><th>Environment</th><th>Sink</th></tr></thead><tbody><tr><td>Development</td><td>Console</td></tr><tr><td>Production</td><td>Console + Seq</td></tr></tbody></table><p>Seq provides a UI for querying structured logs by any property. See <a href="./architecture.html">architecture.md</a> for deployment details.</p><p>Noisy framework logs are suppressed in config:</p><div class="language-json"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki"><code><span class="line"><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C792EA;">Serilog</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#89DDFF;">&quot;</span><span style="color:#FFCB6B;">MinimumLevel</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#A6ACCD;">      </span><span style="color:#89DDFF;">&quot;</span><span style="color:#F78C6C;">Default</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">Information</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#A6ACCD;">      </span><span style="color:#89DDFF;">&quot;</span><span style="color:#F78C6C;">Override</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#A6ACCD;">        </span><span style="color:#89DDFF;">&quot;</span><span style="color:#F07178;">Microsoft</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">Warning</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#A6ACCD;">        </span><span style="color:#89DDFF;">&quot;</span><span style="color:#F07178;">Microsoft.EntityFrameworkCore</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">Warning</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#A6ACCD;">      </span><span style="color:#89DDFF;">}</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#89DDFF;">}</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#89DDFF;">}</span></span>
<span class="line"><span style="color:#89DDFF;">}</span></span>
<span class="line"></span></code></pre></div><p>Without this, EF Core query logs and <a href="http://ASP.NET" target="_blank" rel="noreferrer">ASP.NET</a> request pipeline logs dominate the output.</p>`,50),t=[l];function r(p,c,i,d,D,y){return a(),e("div",null,t)}const h=s(o,[["render",r]]);export{F as __pageData,h as default};
